class Engine:
    def __init__(self, hp):
        self.hp = hp
    def start(self):
        return f'Engine ({self.hp}hp) started'

class GPS:
    def navigate(self, dest):
        return f'Navigating to {dest}'

class Car:
    def __init__(self, brand, engine, gps):
        self.brand = brand
        self.engine = engine  # has-a Engine
        self.gps = gps        # has-a GPS

    def drive(self, dest):
        msg = self.engine.start()
        nav = self.gps.navigate(dest)
        return f'{self.brand}: {msg}. {nav}'

# Compose objects
my_car = Car('Tesla', Engine(300), GPS())
print(my_car.drive('Airport'))

