class Battery:
    def __init__(self, capacity):
        self.capacity = capacity
class Phone:
    def __init__(self, brand, battery):
        self.brand = brand
        self.battery = battery
    def info(self):
        return f'Brand: {self.brand}, Battery: {self.battery.capacity}mah'
p = Phone('Apple', Battery(3000))
assert p.info() == 'Brand: Apple, Battery: 3000mah'
